import { writable } from 'svelte/store';

export const exploreActive = writable(false);
export const exploreFailure = writable(null);

export function setExploreActive(active) {
	exploreActive.set(Boolean(active));
}

export function setExploreFailure(failure) {
	exploreFailure.set(failure || null);
}

export function clearExploreFailure() {
	exploreFailure.set(null);
}
